import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, Cpu, Zap } from 'lucide-react';

const LoginPage = () => {
  const [email, setEmail]       = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading]   = useState(false);
  const [focused, setFocused]   = useState(null); // 'email' | 'password' | null

  const { login }  = useAuth();
  const navigate   = useNavigate();

  /* ── Laser scan re-trigger on mount ── */
  const [scanKey, setScanKey] = useState(0);
  useEffect(() => { setScanKey(k => k + 1); }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please enter your credentials.');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back to Finify!');
      navigate('/dashboard');
    } catch {
      toast.error('Invalid credentials. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    /* ── Outer Shell — fills viewport, centers card ── */
    <div className="institutional-shell">

      {/* ── Ambient corner glow (fixed, out of flow) ── */}
      <div
        aria-hidden="true"
        style={{
          position: 'fixed',
          top: '-120px',
          left: '-120px',
          width: '400px',
          height: '400px',
          background: 'var(--accent-glow)',
          borderRadius: '50%',
          filter: 'blur(90px)',
          opacity: 0.6,
          pointerEvents: 'none',
          zIndex: 0,
        }}
      />
      <div
        aria-hidden="true"
        style={{
          position: 'fixed',
          bottom: '-80px',
          right: '-80px',
          width: '300px',
          height: '300px',
          background: 'var(--accent-glow)',
          borderRadius: '50%',
          filter: 'blur(100px)',
          opacity: 0.35,
          pointerEvents: 'none',
          zIndex: 0,
        }}
      />

      {/* ── Vault Card ── */}
      <div className="vault-card reveal-node" style={{ position: 'relative', overflow: 'hidden' }}>

        {/* Laser scanner stripe */}
        <span key={scanKey} className="animate-laser" aria-hidden="true" />

        {/* ── Header ── */}
        <div style={{ textAlign: 'center', marginBottom: '2.5rem' }}>
          <div style={{ display: 'flex', justifyContent: 'center', marginBottom: '1rem' }}>
            <div style={{
              width: '56px',
              height: '56px',
              borderRadius: '16px',
              background: 'var(--accent-muted)',
              border: '1px solid var(--accent-primary)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 0 24px var(--accent-glow)',
            }}>
              <Cpu size={26} color="var(--accent-primary)" />
            </div>
          </div>

          <h1 style={{
            fontSize: '1.75rem',
            fontWeight: 300,
            letterSpacing: '-0.02em',
            color: 'var(--text-primary)',
            margin: '0 0 0.4rem',
          }}>
            Welcome Back
          </h1>
          <p style={{
            fontSize: '0.65rem',
            textTransform: 'uppercase',
            letterSpacing: '0.25em',
            color: 'var(--text-muted)',
            margin: 0,
          }}>
            Sign in to access your node
          </p>
        </div>

        {/* ── Form ── */}
        <form onSubmit={handleSubmit} noValidate style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>

          {/* Email */}
          <div>
            <label
              htmlFor="email"
              style={{
                display: 'block',
                fontSize: '0.65rem',
                fontWeight: 700,
                textTransform: 'uppercase',
                letterSpacing: '0.18em',
                color: focused === 'email' ? 'var(--accent-primary)' : 'var(--text-muted)',
                marginBottom: '0.5rem',
                transition: 'color 0.2s ease',
              }}
            >
              Email Address
            </label>
            <input
              id="email"
              type="email"
              placeholder="operator@finify.ai"
              value={email}
              onChange={e => setEmail(e.target.value)}
              onFocus={() => setFocused('email')}
              onBlur={() => setFocused(null)}
              className="cyber-input"
              autoComplete="email"
              required
            />
          </div>

          {/* Password */}
          <div>
            <label
              htmlFor="password"
              style={{
                display: 'block',
                fontSize: '0.65rem',
                fontWeight: 700,
                textTransform: 'uppercase',
                letterSpacing: '0.18em',
                color: focused === 'password' ? 'var(--accent-primary)' : 'var(--text-muted)',
                marginBottom: '0.5rem',
                transition: 'color 0.2s ease',
              }}
            >
              Master Key
            </label>
            <div style={{ position: 'relative' }}>
              <input
                id="password"
                type={showPass ? 'text' : 'password'}
                placeholder="••••••••"
                value={password}
                onChange={e => setPassword(e.target.value)}
                onFocus={() => setFocused('password')}
                onBlur={() => setFocused(null)}
                className="cyber-input"
                style={{ paddingRight: '3rem' }}
                autoComplete="current-password"
                required
              />
              <button
                type="button"
                onClick={() => setShowPass(v => !v)}
                aria-label={showPass ? 'Hide password' : 'Show password'}
                style={{
                  position: 'absolute',
                  right: '1rem',
                  top: '50%',
                  transform: 'translateY(-50%)',
                  background: 'none',
                  border: 'none',
                  padding: 0,
                  cursor: 'pointer',
                  color: 'var(--text-muted)',
                  display: 'flex',
                  alignItems: 'center',
                  transition: 'color 0.2s ease',
                }}
                onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
                onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
              >
                {showPass ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </div>
          </div>

          {/* Forgot password — optional UX affordance */}
          <div style={{ textAlign: 'right', marginTop: '-0.5rem' }}>
            <Link
              to="/forgot-password"
              style={{
                fontSize: '0.65rem',
                textTransform: 'uppercase',
                letterSpacing: '0.15em',
                color: 'var(--text-muted)',
                textDecoration: 'none',
                transition: 'color 0.2s ease',
              }}
              onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
              onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
            >
              Forgot key?
            </Link>
          </div>

          {/* Submit */}
          <button
            type="submit"
            className="cyber-btn"
            disabled={loading}
            style={{ marginTop: '0.5rem' }}
          >
            {loading ? (
              <>
                <Zap size={14} style={{ animation: 'pulse 1s ease-in-out infinite' }} />
                SYNCHRONIZING...
              </>
            ) : (
              'Access Node'
            )}
          </button>
        </form>

        {/* ── Footer ── */}
        <div style={{
          marginTop: '2rem',
          paddingTop: '1.5rem',
          borderTop: '1px solid var(--surface-border)',
          textAlign: 'center',
        }}>
          <p style={{
            fontSize: '0.65rem',
            textTransform: 'uppercase',
            letterSpacing: '0.2em',
            color: 'var(--text-muted)',
            margin: 0,
          }}>
            No account?{' '}
            <Link
              to="/register"
              style={{
                color: 'var(--accent-primary)',
                textDecoration: 'none',
                fontWeight: 700,
                transition: 'opacity 0.2s ease',
              }}
              onMouseEnter={e => e.currentTarget.style.opacity = '0.75'}
              onMouseLeave={e => e.currentTarget.style.opacity = '1'}
            >
              Create one
            </Link>
          </p>
        </div>
      </div>
    </div>
  );
};

export default LoginPage;
